import React, { useState } from 'react';

function RegisterPage() {
  // Step 4.2: Initializing state for form inputs [cite: 247]
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    confirmPassword: ''
  });

  // State for validation errors and submission status [cite: 250, 254]
  const [error, setError] = useState('');
  const [submitted, setSubmitted] = useState(false);

  // Step 4.2: Handling input changes to keep UI in sync [cite: 247, 248]
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
    // Clear error message when user starts typing again
    if (error) setError('');
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Bonus Task: Basic Validation [cite: 254]
    if (!formData.username || !formData.email || !formData.password) {
      setError('All fields are required!');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match!');
      return;
    }

    // Step 4.3: Conditional Rendering (Success State) [cite: 250, 251]
    console.log('Registration Data:', formData);
    setSubmitted(true);
  };

  // Step 4.3: Show success message instead of the form [cite: 252]
  if (submitted) {
    return (
      <div className="container">
        <div className="success-card">
          <h2>Welcome aboard, {formData.username}!</h2>
          <p>Your account has been created successfully.</p>
          <button onClick={() => window.location.href = '/home'}>Go to Home</button>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <h1>Create an Account</h1>
      <p>Join our community of bloggers today.</p>
      
      {/* Rendering error message if validation fails [cite: 254] */}
      {error && <p style={{ color: 'red', fontWeight: 'bold' }}>{error}</p>}

      <form onSubmit={handleSubmit} className="auth-form">
        <div className="form-group">
          <label htmlFor="username">Username</label>
          <input
            type="text"
            name="username"
            id="username"
            value={formData.username}
            onChange={handleChange}
            placeholder="Choose a username"
          />
        </div>

        <div className="form-group">
          <label htmlFor="email">Email Address</label>
          <input
            type="email"
            name="email"
            id="email"
            value={formData.email}
            onChange={handleChange}
            placeholder="Email@example.com"
          />
        </div>

        <div className="form-group">
          <label htmlFor="password">Password</label>
          <input
            type="password"
            name="password"
            id="password"
            value={formData.password}
            onChange={handleChange}
            placeholder="Create a password"
          />
        </div>

        <div className="form-group">
          <label htmlFor="confirmPassword">Confirm Password</label>
          <input
            type="password"
            name="confirmPassword"
            id="confirmPassword"
            value={formData.confirmPassword}
            onChange={handleChange}
            placeholder="Repeat your password"
          />
        </div>

        <button type="submit" className="btn-submit">Register</button>
      </form>
    </div>
  );
}

export default RegisterPage;
